css:
@page {
        size: A4 portrait;
        @frame bg1f  { -pdf-frame-content: bg1;  left: 20pt; top: 14pt; width: 555pt; height: 86.5pt; }
        @frame bgg1f { -pdf-frame-content: bgg1; left: 20pt; top: 102.5pt; width: 555pt; height: 138.5pt; }
        @frame bgb1f { -pdf-frame-content: bgb1; left: 20pt; top: 238pt; width: 555pt; height: 30pt; }
        @frame bg2f  { -pdf-frame-content: bg2;  left: 20pt; top: 292pt; width: 555pt; height: 86.5pt; }
        @frame bgg2f { -pdf-frame-content: bgg2; left: 20pt; top: 380.5pt; width: 555pt; height: 138.5pt; }
        @frame bgb2f { -pdf-frame-content: bgb2; left: 20pt; top: 516pt; width: 555pt; height: 30pt; }
        @frame bg3f  { -pdf-frame-content: bg3;  left: 20pt; top: 572pt; width: 555pt; height: 86.5pt; }
        @frame bgg3f { -pdf-frame-content: bgg3; left: 20pt; top: 660.5pt; width: 555pt; height: 138.5pt; }
        @frame bgb3f { -pdf-frame-content: bgb3; left: 20pt; top: 796pt; width: 555pt; height: 30pt; }
        @frame fgh1f { -pdf-frame-content: fgh1; left: 20pt; top: 30pt; width: 555pt; height: 62pt; }
        @frame fgi1f { -pdf-frame-content: fgi1; left: 20pt; top: 117pt; width: 555pt; height: 150pt; }
        @frame fgb1f { -pdf-frame-content: fgb1; left: 20pt; top: 238pt; width: 555pt; height: 30pt; }
        @frame fgh2f { -pdf-frame-content: fgh2; left: 20pt; top: 308pt; width: 555pt; height: 62pt; }
        @frame fgi2f { -pdf-frame-content: fgi2; left: 20pt; top: 395pt; width: 555pt; height: 150pt; }
        @frame fgb2f { -pdf-frame-content: fgb2; left: 20pt; top: 516pt; width: 555pt; height: 30pt; }
        @frame fgh3f { -pdf-frame-content: fgh3; left: 20pt; top: 588pt; width: 555pt; height: 62pt; }
        @frame fgi3f { -pdf-frame-content: fgi3; left: 20pt; top: 675pt; width: 555pt; height: 150pt; }
        @frame fgb3f { -pdf-frame-content: fgb3; left: 20pt; top: 796pt; width: 555pt; height: 30pt; }
        @frame mainf { left: 20pt; top: 838pt; width: 555pt; height: 3pt; }
    }

    body, pre {
        font-family: HeiseiMin-W3;
        margin: 0;
        padding: 0;
    }

    .titlebar td { padding: 0; font-size: 14px; }
    .title-box {
        background-color: #000000;
        color: #ffffff;
        text-align: center;
        font-size: 14px;
        height: 18pt;
        padding-top: 6px;
        padding-bottom: 0px;
    }

    .hdr td { padding: 0; vertical-align: top; font-size: 11px; }
    .s10 { font-size: 10px; }
    .s11 { font-size: 11px; }
    .cname { font-size: 14px; }
    .comp { font-size: 13px; }

    .sp td { padding: 0; font-size: 8px; height: 60pt; }
    .msg td {
        padding: 0;
        font-size: 9px;
        text-align: right;
        vertical-align: bottom;
        height: 9pt;
    }

    .grid th {
        font-size: 10px;
        font-weight: normal;
        text-align: center;
        height: 12pt;
        border-top: 1px solid #000000;
        border-bottom: 1px solid #000000;
        border-left: 1px solid #000000;
        padding: 3px 2px 1px 2px;
    }
    .thlast {
        font-size: 10px;
        font-weight: normal;
        text-align: center;
        height: 12pt;
        border-top: 1px solid #000000;
        border-bottom: 1px solid #000000;
        border-left: 1px solid #000000;
        border-right: 1px solid #000000;
        padding: 3px 2px 1px 2px;
    }
    .ryoshuin {
        font-size: 12px;
        font-weight: normal;
        color: #808080;
        text-align: center;
        height: 12pt;
        border-top: 1px solid #000000;
        border-bottom: 1px solid #000000;
        border-left: 1px solid #000000;
        border-right: 1px solid #000000;
        padding: 3px 2px 1px 2px;
    }

    /* ゼブラ行: g=グレー w=白 / l=右端 / b=最下行 */
    .zg   { font-size: 10px; height: 15pt; padding: 1px 4px 0px 4px; vertical-align: top; background-color: #D9D9D9; border-left: 1px solid #000000; }
    .zw   { font-size: 10px; height: 15pt; padding: 1px 4px 0px 4px; vertical-align: top; border-left: 1px solid #000000; }
    .zgl  { font-size: 10px; height: 15pt; padding: 1px 4px 0px 4px; vertical-align: top; background-color: #D9D9D9; border-left: 1px solid #000000; border-right: 1px solid #000000; }
    .zwl  { font-size: 10px; height: 15pt; padding: 1px 4px 0px 4px; vertical-align: top; border-left: 1px solid #000000; border-right: 1px solid #000000; }
    .zgb  { font-size: 10px; height: 15pt; padding: 1px 4px 0px 4px; vertical-align: top; background-color: #D9D9D9; border-left: 1px solid #000000; border-bottom: 1px solid #000000; }
    .zwb  { font-size: 10px; height: 15pt; padding: 1px 4px 0px 4px; vertical-align: top; border-left: 1px solid #000000; border-bottom: 1px solid #000000; }
    .zgbl { font-size: 10px; height: 15pt; padding: 1px 4px 0px 4px; vertical-align: top; background-color: #D9D9D9; border-left: 1px solid #000000; border-bottom: 1px solid #000000; border-right: 1px solid #000000; }
    .zwbl { font-size: 10px; height: 15pt; padding: 1px 4px 0px 4px; vertical-align: top; border-left: 1px solid #000000; border-bottom: 1px solid #000000; border-right: 1px solid #000000; }

    /* 前景データ行（透明・罫線なし） */
    .drow td {
        font-size: 10px;
        height: 15pt;
        padding: 1px 4px 0px 4px;
        vertical-align: top;
    }
    .drow div { -pdf-word-wrap: CJK; }
    .anchor td { font-size: 1px; height: 1pt; padding: 0; }

    /* 合計チローム(bg) / データ(fg) */
    .tot td { padding: 0; vertical-align: top; font-size: 9px; height: 13pt; }
    .boxtopl { border-top: 1px solid #000000; border-left: 1px solid #000000; }
    .taxnote {
        font-size: 9px;
        text-align: right;
        border-top: 1px solid #000000;
        border-right: 1px solid #000000;
        padding: 3px 4px 0px 4px;
    }
    .sumlabel {
        background-color: #000000;
        color: #ffffff;
        text-align: center;
        font-size: 11px;
        border-left: 1px solid #000000;
        border-bottom: 1px solid #000000;
        padding-top: 4px;
    }
    .sumbox {
        border-top: 1px solid #000000;
        border-right: 1px solid #000000;
        border-bottom: 1px solid #000000;
        border-left: 1px solid #000000;
    }
    .fgb td { padding: 0; vertical-align: top; height: 13pt; }
    .remark { font-size: 9px; padding-top: 3px; }
    .shohinkei { font-size: 10px; text-align: right; padding-top: 4px; }
    .sumval { font-size: 11px; padding-top: 4px; }

    .dcell {
        font-size: 10px;
        height: 15pt;
        padding: 1px 4px 0px 4px;
        vertical-align: top;
    }
    .dcell div { -pdf-word-wrap: CJK; }
    .grid div { -pdf-word-wrap: CJK; }
    .anc { font-size: 1px; height: 1pt; padding: 0; }
